from typing import List
class Solution:
    def countKDifference(self, nums: List[int], k: int) -> int:
        count = 0
        num_counts = {}
        for num in nums:
            if num - k in num_counts:
                count += num_counts[num - k]
            if num + k in num_counts:
                count += num_counts[num + k]
            num_counts[num] = num_counts.get(num, 0) + 1
        return count
```
